      if (ctx.user.role !== "owner") throw new TRPCError3({ code: "FORBIDDEN", message: "\u0641\u0642\u0637 \u0645\u0627\u0644\u0643 \u0627\u0644\u0645\u0643\u062A\u0628 \u064A\u0645\u0643\u0646\u0647 \u062A\u0639\u062F\u064A\u0644 \u0628\u064A\u0627\u0646\u0627\u062A \u0627\u0644\u0645\u0643\u062A\u0628" });
